exercises.solutionCode:
using System;
using System.Collections.Generic;
class Program {
    static void Main() {
        List<string> fruits = new List<string>();
        fruits.Add("Apple");
        fruits.Add("Banana");
        fruits.Add("Cherry");
        fruits.Remove("Banana");
        foreach (string f in fruits) {
            Console.WriteLine(f);
        }
    }
}

